module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output reg mul_en_out,
    output mul_out
);

reg [15:0] partial_products[7:0];
reg [15:0] accumulator;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out <= 1'b0;
        partial_products <= '{default: 16'b0};
        accumulator <= 16'b0;
    end
    else if (mul_en_in) begin
        for (int i = 0; i < 8; i++) begin
            partial_products[i] <= mul_a[i] ? {8'b0, mul_b} << i : 16'b0;
        end
        accumulator <= partial_products[0] + partial_products[1] + partial_products[2] + partial_products[3] +
                       partial_products[4] + partial_products[5] + partial_products[6] + partial_products[7];
        mul_en_out <= 1'b1;
    end
    else begin
        mul_en_out <= 1'b0;
    end
end

assign mul_out = accumulator;

endmodule
